SELECT title FROM articles 
WHERE author_id = (
    SELECT author_id FROM authors 
    WHERE author_name = 'John Doe'
);

SELECT ar.title
FROM articles AS ar
WHERE ar.views_today = (
    SELECT MAX(views_today)
    FROM articles
);

SELECT DISTINCT u.user_name
FROM users u
INNER JOIN article_comments ac ON u.user_id = ac.user_id;
